public class Solution {
    public static long[] solve(long[] nums, long[][] queries) {
        int n = nums.length;
        long[] answer = new long[queries.length];
        int idx = 0;

        // Precompute popcount-depth for each number in nums
        long[] popcountDepth = new long[n];
        for (int i = 0; i < n; i++) {
            popcountDepth[i] = computePopcountDepth(nums[i]);
        }

        // Create a list of frequency maps for each possible depth (0 to 5)
        // Since k can be up to 5, we only need to track depths 0 to 5
        List<TreeSet<Integer>> freqMaps = new ArrayList<>();
        for (int i = 0; i <= 5; i++) {
            freqMaps.add(new TreeSet<>());
        }

        // Initialize frequency maps
        for (int i = 0; i < n; i++) {
            freqMaps.get((int) popcountDepth[i]).add(i);
        }

        // Process each query
        for (long[] query : queries) {
            if (query[0] == 1) {
                // Type 1 query: count numbers in [l, r] with depth k
                int l = (int) query[1];
                int r = (int) query[2];
                int k = (int) query[3];
                long count = 0;

                // Use TreeSet to find the count of indices in [l, r]
                TreeSet<Integer> set = freqMaps.get(k);
                if (set.isEmpty()) {
                    answer[idx++] = 0;
                    continue;
                }

                // Find the lower and upper bounds
                Integer lower = set.floor(r);
                Integer upper = set.ceil(l);

                if (lower == null || upper == null) {
                    answer[idx++] = 0;
                    continue;
                }

                // Count numbers between lower and upper (inclusive)
                long cnt = Collections.reverseOrder().descendingIterator().next();
                answer[idx++] = cnt;
            } else {
                // Type 2 query: update nums[idx] to val
                int idxUpdate = (int) query[1];
                long val = query[2];

                // Remove the old value from its depth's frequency map
                long oldVal = nums[idxUpdate];
                int oldDepth = (int) popcountDepth[idxUpdate];
                freqMaps.get(oldDepth).remove(idxUpdate);

                // Compute the new depth
                int newDepth = (int) computePopcountDepth(val);

                // Add the new value to its depth's frequency map
                freqMaps.get(newDepth).add(idxUpdate);

                // Update nums
                nums[idxUpdate] = val;
            }
        }

        return answer;
    }

    private static long computePopcountDepth(long x) {
        long depth = 0;
        while (x > 0) {
            x = Long.bitCount(x);
            depth++;
        }
        return depth;
    }
}
